What does the following program print?

```cpp
#include <iostream>
#include <vector>
#include <algorithm>
int main()
{
    std::vector<int> v { 5, 3, 8, 1, 9, 3 };
    std::cout << std::count(v.begin(), v.end(), 3) << '\n';
    std::sort(v.begin(), v.end());
    auto it = std::find(v.begin(), v.end(), 8);
    std::cout << (it - v.begin()) << '\n';
    return 0;
}
```

The code below is supposed to find value 7 in the vector and print its index, but it has a bug. What is it?

```cpp
#include <iostream>
#include <vector>
#include <algorithm>
int main()
{
    std::vector<int> v { 3, 7, 5, 1 };
    auto it = std::find(v.begin(), v.end(), 7);
    std::cout << "Index: " << *it << '\n';  // prints the value, not the index
    return 0;
}
```
